    const collectionAttrs = ooxmlXmlAttributes(fieldCollections[0][1] || "");
    const fieldTags = [...(fieldCollections[0][2] || "").matchAll(/<(?:[A-Za-z_][\w.-]*:)?queryTableField\b([^>]*)\/?>/g)];
    const count = Number(collectionAttrs.count);
